  1→import supabase from "./supabase.js";
  2→
  3→const VALID_REACTIONS = ['fire', 'heart', 'mind_blown', 'clap', 'laugh', 'sad'];
  4→
  5→/**
  6→ * Toggle a reaction on a post.
  7→ * - Same emoji = remove reaction
  8→ * - Different emoji = switch reaction
  9→ * - No existing = add reaction
 10→ */
 11→export const toggleReactionService = async (journalId, receiverId, senderId, reactionType) => {
 12→    if (!journalId || !senderId) {
 13→        throw { status: 400, error: 'journalId and senderId are required' };
 14→    }
 15→
 16→    if (!VALID_REACTIONS.includes(reactionType)) {
 17→        throw { status: 400, error: 'invalid reaction type' };
 18→    }
 19→
 20→    const isOwnContent = senderId === receiverId;
 21→
 22→    // Check existing reaction
 23→    const { data: existing, error: fetchErr } = await supabase
 24→        .from('reactions')
 25→        .select('id, reaction_type')
 26→        .eq('user_id', senderId)
 27→        .eq('journal_id', journalId)
 28→        .maybeSingle();
 29→
 30→    if (fetchErr) {
 31→        console.error('error checking existing reaction:', fetchErr.message);
 32→    }
 33→
 34→    if (!existing) {
 35→        // No existing reaction → insert new
 36→        const insertReactionPromise = supabase
 37→            .from('reactions')
 38→            .insert({
 39→                user_id: senderId,
 40→                journal_id: journalId,
 41→                reaction_type: reactionType,
 42→            });
 43→
 44→        const insertNotifPromise = supabase
 45→            .from('notifications')
 46→            .insert({
 47→                sender_id: senderId,
 48→                receiver_id: receiverId,
 49→                journal_id: journalId,
 50→                type: 'reaction',
 51→                reaction_type: reactionType,
 52→                read: false,
 53→            });
 54→
 55→        const [insertReaction, insertNotif] = await Promise.all([
 56→            insertReactionPromise,
 57→            isOwnContent ? Promise.resolve({ error: null }) : insertNotifPromise,
 58→        ]);
 59→
 60→        if (insertReaction.error) {
 61→            console.error('error inserting reaction:', insertReaction.error.message);
 62→            throw { status: 500, error: 'failed to add reaction' };
 63→        }
 64→
 65→        return { message: 'reacted', reaction_type: reactionType };
 66→    }
 67→
 68→    if (existing.reaction_type === reactionType) {
 69→        // Same emoji → remove reaction
 70→        const deleteReactionPromise = supabase
 71→            .from('reactions')
 72→            .delete()
 73→            .eq('id', existing.id);
 74→
 75→        const deleteNotifPromise = supabase
 76→            .from('notifications')
 77→            .delete()
 78→            .eq('sender_id', senderId)
 79→            .eq('receiver_id', receiverId)
 80→            .eq('journal_id', journalId)
 81→            .eq('type', 'reaction');
 82→
 83→        const [deleteReaction, deleteNotif] = await Promise.all([
 84→            deleteReactionPromise,
 85→            deleteNotifPromise,
 86→        ]);
 87→
 88→        if (deleteReaction.error) {
 89→            console.error('error deleting reaction:', deleteReaction.error.message);
 90→            throw { status: 500, error: 'failed to remove reaction' };
 91→        }
 92→
 93→        return { message: 'unreacted', reaction_type: null };
 94→    }
 95→
 96→    // Different emoji → switch reaction
 97→    const updateReactionPromise = supabase
 98→        .from('reactions')
 99→        .update({ reaction_type: reactionType })
100→        .eq('id', existing.id);
101→
102→    // Update notification too
103→    const updateNotifPromise = supabase
104→        .from('notifications')
105→        .update({ reaction_type: reactionType })
106→        .eq('sender_id', senderId)
107→        .eq('receiver_id', receiverId)
108→        .eq('journal_id', journalId)
109→        .eq('type', 'reaction');
110→
111→    const [updateReaction] = await Promise.all([
112→        updateReactionPromise,
113→        isOwnContent ? Promise.resolve({ error: null }) : updateNotifPromise,
114→    ]);
115→
116→    if (updateReaction.error) {
117→        console.error('error updating reaction:', updateReaction.error.message);
118→        throw { status: 500, error: 'failed to switch reaction' };
119→    }
120→
121→    return { message: 'switched', reaction_type: reactionType };
122→};
