    letter-spacing: 0.005rem;
}

.canvas-card-actions{
    display: flex;
    flex-wrap: wrap;
    gap: 0.42rem;
    width: 100%;
    margin-top: -0.1rem;
}

.canvas-card-action-btn{
    border: 1px solid var(--border-card);
