  1→import React, { useState, useRef, useCallback, useEffect } from 'react';
  2→import ReactionPicker from './ReactionPicker';
  3→import { getReactionEmoji } from '../../utils/reactionConfig';
  4→import './reactions.css';
  5→
  6→const ReactionButton = ({ userReaction, reactionCount, onReact, disabled }) => {
  7→    const [showPicker, setShowPicker] = useState(false);
  8→    const hoverTimerRef = useRef(null);
  9→    const leaveTimerRef = useRef(null);
 10→    const longPressTimerRef = useRef(null);
 11→    const containerRef = useRef(null);
 12→
 13→    const handleMouseEnter = useCallback(() => {
 14→        if (leaveTimerRef.current) {
 15→            clearTimeout(leaveTimerRef.current);
 16→            leaveTimerRef.current = null;
 17→        }
 18→        hoverTimerRef.current = setTimeout(() => {
 19→            setShowPicker(true);
 20→        }, 300);
 21→    }, []);
 22→
 23→    const handleMouseLeave = useCallback(() => {
 24→        if (hoverTimerRef.current) {
 25→            clearTimeout(hoverTimerRef.current);
 26→            hoverTimerRef.current = null;
 27→        }
 28→        leaveTimerRef.current = setTimeout(() => {
 29→            setShowPicker(false);
 30→        }, 150);
 31→    }, []);
 32→
 33→    const handleTouchStart = useCallback(() => {
 34→        longPressTimerRef.current = setTimeout(() => {
 35→            setShowPicker(true);
 36→        }, 500);
 37→    }, []);
 38→
 39→    const handleTouchEnd = useCallback(() => {
 40→        if (longPressTimerRef.current) {
 41→            clearTimeout(longPressTimerRef.current);
 42→            longPressTimerRef.current = null;
 43→        }
 44→    }, []);
 45→
 46→    useEffect(() => {
 47→        return () => {
 48→            if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
 49→            if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
 50→            if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
 51→        };
 52→    }, []);
 53→
 54→    const handleQuickClick = useCallback((e) => {
 55→        e.preventDefault();
 56→        e.stopPropagation();
 57→        if (disabled) return;
 58→
 59→        if (showPicker) {
 60→            setShowPicker(false);
 61→            return;
 62→        }
 63→
 64→        // Quick tap: toggle heart (or remove current reaction)
 65→        if (userReaction) {
 66→            onReact(userReaction); // toggle off
 67→        } else {
 68→            onReact('heart'); // default to heart
 69→        }
 70→    }, [userReaction, onReact, disabled, showPicker]);
 71→
 72→    const handlePickerSelect = useCallback((reactionType) => {
 73→        setShowPicker(false);
 74→        onReact(reactionType);
 75→    }, [onReact]);
 76→
 77→    const hasReaction = !!userReaction;
 78→    const displayEmoji = hasReaction ? getReactionEmoji(userReaction) : null;
 79→
 80→    return (
 81→        <div
 82→            className="reaction-button-container"
 83→            ref={containerRef}
 84→            onMouseEnter={handleMouseEnter}
 85→            onMouseLeave={handleMouseLeave}
 86→            onTouchStart={handleTouchStart}
 87→            onTouchEnd={handleTouchEnd}
 88→        >
 89→            <div
 90→                className={`reaction-button ${hasReaction ? 'has-reaction' : ''}`}
 91→                onClick={handleQuickClick}
 92→            >
 93→                {hasReaction ? (
 94→                    <span className="reaction-button-emoji">{displayEmoji}</span>
 95→                ) : (
 96→                    <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
 97→                        <g id="style=fill">
