364→export const addFollowsService = async(followerId, followingId) => {
365→    if(!followerId || !followingId){
366→        console.error('followerId or followingId is undefined');
367→        throw {status: 400, error: 'followerId or followingId is undefined'};
368→    }
369→
370→    const {data: existing, error: errorExisting} = await supabase
371→    .from('follows')
372→    .select('*')
373→    .eq('follower_id', followerId)
374→    .eq('following_id', followingId)
375→    .maybeSingle();
376→
377→    if(errorExisting){
378→        console.error('supabase error while checking existing following:', errorExisting.message);
379→        throw {status: 500, error: 'supabase error while checking existing following'}
380→    }
381→
382→    if(existing){
383→        const {data: removeData, error: errorRemoveData} = await supabase
384→        .from('follows')
385→        .delete()
386→        .eq('follower_id', followerId)
387→        .eq('following_id', followingId)
388→
389→        if(errorRemoveData){
390→            console.error('supabase error while deleting follow data:', errorRemoveData.message);
391→            throw {status: 500, error: 'supabase error while deleting follow data'};
392→        }
393→
394→        return {message: 'deleted follows data'};
395→    } else {
396→        const data = {
397→            follower_id: followerId,
398→            following_id: followingId,
399→        }
400→
401→        const {data: inserData,  error: errorInserData} = await supabase
402→        .from('follows')
403→        .insert(data)
404→
405→        if(errorInserData){
406→            console.error('supabase error while inserting follow data:', errorInserData.message);
407→            throw {status: 500, error: 'supabase error while inserting follow data:'}
408→        }
409→
410→        return {message: 'success'};
411→    }
